// AUTO-GENERATED. Base64-embedded fonts for the share poster, SUBSETTED to
// printable ASCII (digits/Latin/punctuation) to keep the export fast and the
// serialized SVG small. Self-contained @font-face so the fonts render inside
// the SVG -> <img> -> canvas PNG export sandbox (no network there). Families:
//   TSCond = Saira Condensed (600/800) - hero numbers + labels
//   TSSign = Caveat (600) - handwritten Training Studio signature
// CJK (e.g. a location string) falls back to the system stack on purpose.
export const POSTER_FONT_CSS = "@font-face{font-family:'TSCond';font-style:normal;font-weight:600;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'TSCond';font-style:normal;font-weight:800;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'TSSign';font-style:normal;font-weight:600;font-display:block;src:url(data:font/woff2;base64,) format('woff2');}";
